function TripPlanner() {
  const [from, setFrom] = React.useState('REPLACE_WITH_ORIGIN');
  const [to, setTo] = React.useState('REPLACE_WITH_DESTINATION');
  const [mpg, setMpg] = React.useState(30);
  const [gasPrice, setGasPrice] = React.useState(3.50);

  // Mock distance calculation
  const distance = from && to ? Math.abs(from.length - to.length) * 15 + 50 : 0;
  const gallons = distance / mpg;
  const cost = gallons * gasPrice;
  const hours = distance / 60;

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Trip Planner</div>
      <div style={{display:'flex',flexDirection:'column',gap:8,marginBottom:12}}>
        <input value={from} onChange={e=>setFrom(e.target.value)}
          style={{padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14}} placeholder="From…"/>
        <input value={to} onChange={e=>setTo(e.target.value)}
          style={{padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14}} placeholder="To…"/>
      </div>
      <div style={{display:'flex',gap:8,marginBottom:12}}>
        <div style={{flex:1}}>
          <div style={{fontSize:11,color:'#888',marginBottom:4}}>MPG</div>
          <input type="number" value={mpg} onChange={e=>setMpg(Number(e.target.value))}
            style={{width:'100%',padding:'8px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}/>
        </div>
        <div style={{flex:1}}>
          <div style={{fontSize:11,color:'#888',marginBottom:4}}>Gas $/gal</div>
          <input type="number" step="0.01" value={gasPrice} onChange={e=>setGasPrice(Number(e.target.value))}
            style={{width:'100%',padding:'8px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}/>
        </div>
      </div>
      {distance > 0 && (
        <div style={{background:'#f5f5f5',borderRadius:12,padding:16,marginTop:'auto'}}>
          <div style={{display:'flex',justifyContent:'space-between',marginBottom:8}}>
            <span style={{color:'#888'}}>Distance</span>
            <span style={{fontWeight:600}}>{distance} mi</span>
          </div>
          <div style={{display:'flex',justifyContent:'space-between',marginBottom:8}}>
            <span style={{color:'#888'}}>Est. Time</span>
            <span style={{fontWeight:600}}>{Math.floor(hours)}h {Math.round((hours%1)*60)}m</span>
          </div>
          <div style={{display:'flex',justifyContent:'space-between'}}>
            <span style={{color:'#888'}}>Fuel Cost</span>
            <span style={{fontWeight:600,color:'#007AFF'}}>${cost.toFixed(2)}</span>
          </div>
        </div>
      )}
    </div>
  );
}
render(<TripPlanner/>);
